import CalendarIcon from '../assets/icons/CalendarIcon';
import ClockIcon from '../assets/icons/ClockIcon';
import { LocationIcon } from '../assets/icons/LocationIcon';

function Details() {
  return (
    <div className="w-full m-auto flex flex-col items-center justify-center gap-10 bg-[#656c64] py-16">
      <h2 className="text-white text-4xl">Detalles de la boda</h2>
      <div className="w-full flex justify-center  items-center gap-10">
        <div className="flex flex-col items-center justify-center gap-2">
          <CalendarIcon size="50" />
          <p className="text-primary text-lg underline">Fecha</p>
        </div>

        <div className="flex flex-col items-center justify-center gap-2">
          <ClockIcon size="50" />
          <p className="text-primary text-lg underline">Horario</p>
        </div>

        <div className="flex flex-col items-center justify-center gap-2">
          <LocationIcon size="50" />
          <p className="text-primary text-lg underline">Ubicación</p>
        </div>
      </div>
    </div>
  );
}

export default Details;
